fun hamiltonianPath(arr: IntArray): Int {
    val n = arr[0]; val m = arr[1]
    if (n <= 1) return 1
    val adj = Array(n) { BooleanArray(n) }
    for (i in 0 until m) {
        val u = arr[2+2*i]; val v = arr[3+2*i]
        adj[u][v] = true; adj[v][u] = true
    }
    val full = (1 shl n) - 1
    val dp = Array(1 shl n) { BooleanArray(n) }
    for (i in 0 until n) dp[1 shl i][i] = true
    for (mask in 1..full) for (i in 0 until n) {
        if (!dp[mask][i]) continue
        for (j in 0 until n) if (mask and (1 shl j) == 0 && adj[i][j])
            dp[mask or (1 shl j)][j] = true
    }
    for (i in 0 until n) if (dp[full][i]) return 1
    return 0
}

def hamiltonian_path(arr: list[int]) -> int:
    n = arr[0]
    m = arr[1]
    if n <= 1:
        return 1
    adj = [[False] * n for _ in range(n)]
    for i in range(m):
        u, v = arr[2 + 2 * i], arr[3 + 2 * i]
        adj[u][v] = True
        adj[v][u] = True

    full = (1 << n) - 1
    dp = [[False] * n for _ in range(1 << n)]
    for i in range(n):
        dp[1 << i][i] = True

    for mask in range(1, 1 << n):
        for i in range(n):
            if not dp[mask][i]:
                continue
            for j in range(n):
                if mask & (1 << j) == 0 and adj[i][j]:
                    dp[mask | (1 << j)][j] = True

    for i in range(n):
        if dp[full][i]:
            return 1
    return 0

pub fn hamiltonian_path(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let m = arr[1] as usize;
    if n <= 1 { return 1; }
    let mut adj = vec![vec![false; n]; n];
    for i in 0..m {
        let u = arr[2+2*i] as usize;
        let v = arr[3+2*i] as usize;
        adj[u][v] = true; adj[v][u] = true;
    }
    let full = (1usize << n) - 1;
    let mut dp = vec![vec![false; n]; 1 << n];
    for i in 0..n { dp[1 << i][i] = true; }
    for mask in 1..=full {
        for i in 0..n {
            if !dp[mask][i] { continue; }
            for j in 0..n {
                if mask & (1 << j) == 0 && adj[i][j] {
                    dp[mask | (1 << j)][j] = true;
                }
            }
        }
    }
    for i in 0..n { if dp[full][i] { return 1; } }
    0
}

